//! Performance benchmarks for rust-serv
//!
//! This benchmark suite tests the performance of key components:
//! - File service operations
//! - Compression algorithms
//! - Path validation
//! - MIME type detection
//! - Concurrent request handling

use criterion::{black_box, criterion_group, criterion_main, Criterion, BenchmarkId};
use rust_serv::file_service::FileService;
use rust_serv::path_security::PathValidator;
use rust_serv::mime_types::MimeDetector;
use rust_serv::handler::compress;
use std::path::PathBuf;
use std::fs;
use tempfile::TempDir;

/// Benchmark file reading operations
fn bench_file_service(c: &mut Criterion) {
    let temp_dir = TempDir::new().unwrap();

    // Test different file sizes
    let sizes = vec![1024, 10 * 1024, 100 * 1024, 1024 * 1024]; // 1KB, 10KB, 100KB, 1MB

    let mut group = c.benchmark_group("file_service_read");

    for size in sizes {
        let file_path = temp_dir.path().join(format!("test_{}.txt", size));
        let content = "a".repeat(size);
        fs::write(&file_path, content).unwrap();

        group.bench_with_input(BenchmarkId::new("read_file", size), &file_path, |b, path| {
            b.iter(|| {
                black_box(FileService::read_file(black_box(path)).unwrap())
            });
        });
    }

    group.finish();
}

/// Benchmark Gzip compression
fn bench_gzip_compression(c: &mut Criterion) {
    let mut group = c.benchmark_group("gzip_compression");

    // Test different data patterns
    let test_data = vec![
        ("repetitive", "a".repeat(100_000).into_bytes()),
        ("text", "The quick brown fox jumps over the lazy dog. ".repeat(5000).into_bytes()),
        ("json", r#"{"name":"test","value":123,"nested":{"key":"value"},"array":[1,2,3]}"#.repeat(1000).into_bytes()),
        ("html", "<html><body><div>test</div></body></html>".repeat(5000).into_bytes()),
    ];

    for (name, data) in test_data {
        group.bench_with_input(BenchmarkId::new(name, data.len()), &data, |b, input| {
            b.iter(|| {
                black_box(compress::compress_gzip(black_box(input)).unwrap())
            });
        });
    }

    group.finish();
}

/// Benchmark Brotli compression
fn bench_brotli_compression(c: &mut Criterion) {
    let mut group = c.benchmark_group("brotli_compression");

    let test_data = vec![
        ("repetitive", "a".repeat(100_000).into_bytes()),
        ("text", "The quick brown fox jumps over the lazy dog. ".repeat(5000).into_bytes()),
        ("json", r#"{"name":"test","value":123,"nested":{"key":"value"},"array":[1,2,3]}"#.repeat(1000).into_bytes()),
        ("html", "<html><body><div>test</div></body></html>".repeat(5000).into_bytes()),
    ];

    for (name, data) in test_data {
        group.bench_with_input(BenchmarkId::new(name, data.len()), &data, |b, input| {
            b.iter(|| {
                black_box(compress::compress_brotli(black_box(input)).unwrap())
            });
        });
    }

    group.finish();
}

/// Benchmark path validation
fn bench_path_validation(c: &mut Criterion) {
    let validator = PathValidator::new(PathBuf::from("/var/www"));

    let mut group = c.benchmark_group("path_validation");

    let test_paths = vec![
        ("valid", "/var/www/index.html"),
        ("nested", "/var/www/static/css/style.css"),
        ("traversal", "/var/www/../../../etc/passwd"),
        ("deep", "/var/www/a/b/c/d/e/f/g/h/index.html"),
    ];

    for (name, path) in test_paths {
        let path_buf = PathBuf::from(path);
        group.bench_with_input(BenchmarkId::new(name, path), &path_buf, |b, input| {
            b.iter(|| {
                black_box(validator.validate(black_box(input)))
            });
        });
    }

    group.finish();
}

/// Benchmark MIME type detection
fn bench_mime_detection(c: &mut Criterion) {
    let mut group = c.benchmark_group("mime_detection");

    let test_files = vec![
        ("html", "index.html"),
        ("css", "style.css"),
        ("js", "app.js"),
        ("png", "image.png"),
        ("jpg", "photo.jpg"),
        ("json", "data.json"),
        ("xml", "config.xml"),
    ];

    for (name, filename) in test_files {
        let path = PathBuf::from(filename);
        group.bench_with_input(BenchmarkId::new(name, filename), &path, |b, input| {
            b.iter(|| {
                black_box(MimeDetector::detect(black_box(input)))
            });
        });
    }

    group.finish();
}

/// Benchmark compression decision logic
fn bench_compression_decision(c: &mut Criterion) {
    let mut group = c.benchmark_group("compression_decision");

    let content_types = vec![
        ("html", "text/html"),
        ("css", "text/css"),
        ("javascript", "text/javascript"),
        ("json", "application/json"),
        ("image", "image/jpeg"),
        ("video", "video/mp4"),
        ("audio", "audio/mpeg"),
        ("gzip", "application/gzip"),
        ("zip", "application/zip"),
    ];

    for (name, content_type) in content_types {
        group.bench_with_input(BenchmarkId::new(name, content_type), &content_type, |b, input| {
            b.iter(|| {
                black_box(rust_serv::handler::should_skip_compression(black_box(input)))
            });
        });
    }

    group.finish();
}

/// Benchmark ETag generation
fn bench_etag_generation(c: &mut Criterion) {
    let temp_dir = TempDir::new().unwrap();
    let test_file = temp_dir.path().join("test.txt");
    fs::write(&test_file, "test content").unwrap();

    let mut group = c.benchmark_group("etag_generation");

    group.bench_function("generate_etag", |b| {
        b.iter(|| {
            let metadata = fs::metadata(&test_file).unwrap();
            let size = metadata.len();
            let modified = metadata.modified().unwrap();
            let duration = modified.duration_since(std::time::UNIX_EPOCH).unwrap();
            black_box(format!(r#""{}-{}""#, duration.as_secs(), size))
        });
    });

    group.finish();
}

/// Benchmark directory listing
fn bench_directory_listing(c: &mut Criterion) {
    let temp_dir = TempDir::new().unwrap();

    // Create directories with different numbers of files
    let file_counts = vec![10, 100, 1000];

    let mut group = c.benchmark_group("directory_listing");

    for count in file_counts {
        let test_dir = temp_dir.path().join(format!("dir_{}", count));
        fs::create_dir_all(&test_dir).unwrap();

        for i in 0..count {
            let file_path = test_dir.join(format!("file_{}.txt", i));
            fs::write(&file_path, "content").unwrap();
        }

        group.bench_with_input(BenchmarkId::new("list", count), &test_dir, |b, path| {
            b.iter(|| {
                black_box(FileService::list_directory(black_box(path)).unwrap())
            });
        });
    }

    group.finish();
}

criterion_group!(
    benches,
    bench_file_service,
    bench_gzip_compression,
    bench_brotli_compression,
    bench_path_validation,
    bench_mime_detection,
    bench_compression_decision,
    bench_etag_generation,
    bench_directory_listing
);

criterion_main!(benches);

/// Example: Add Header Plugin
/// 
/// A simple plugin that adds custom headers to all responses

use rust_serv_plugin::*;
use std::collections::HashMap;

#[derive(Debug)]
pub struct AddHeaderPlugin {
    metadata: PluginMetadata,
    header_name: String,
    header_value: String,
}

impl AddHeaderPlugin {
    pub fn new() -> Self {
        Self {
            metadata: PluginMetadata {
                id: "com.example.add-header".to_string(),
                name: "Add Header Plugin".to_string(),
                version: "1.0.0".to_string(),
                description: "Adds custom headers to responses".to_string(),
                author: "Your Name".to_string(),
                homepage: Some("https://github.com/imnull/rust-serv".to_string()),
                license: "MIT".to_string(),
                min_server_version: "0.3.0".to_string(),
                priority: 50,
                capabilities: vec!["ModifyResponse".to_string()],
                permissions: vec![],
            },
            header_name: "X-Powered-By".to_string(),
            header_value: "rust-serv".to_string(),
        }
    }
}

impl Default for AddHeaderPlugin {
    fn default() -> Self {
        Self::new()
    }
}

impl Plugin for AddHeaderPlugin {
    fn metadata(&self) -> &PluginMetadata {
        &self.metadata
    }

    fn on_load(&mut self, config: &PluginConfig) -> Result<(), PluginError> {
        // 从配置读取 header 名称和值
        if let Some(name) = config.get::<String>("header_name") {
            self.header_name = name;
        }
        if let Some(value) = config.get::<String>("header_value") {
            self.header_value = value;
        }

        // 日志输出
        println!("Plugin loaded: {} v{}", self.metadata.name, self.metadata.version);
        println!("Header: {} = {}", self.header_name, self.header_value);

        Ok(())
    }

    fn on_response(&mut self, response: &mut PluginResponse) -> Result<PluginAction, PluginError> {
        // 为响应添加自定义 Header
        response.headers.insert(
            self.header_name.clone(),
            self.header_value.clone(),
        );

        // 继续执行下一个插件
        Ok(PluginAction::Continue)
    }

    fn on_unload(&mut self) -> Result<(), PluginError> {
        println!("Plugin unloaded: {}", self.metadata.name);
        Ok(())
    }
}

// 导出插件
rust_serv_plugin::export_plugin!(AddHeaderPlugin);

/// Plugin SDK - 插件开发接口定义
/// 
/// 本模块定义了插件开发者需要实现的核心 trait 和数据结构

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::path::Path;
use thiserror::Error;

// ============================================================================
// 插件元数据
// ============================================================================

/// 插件元数据
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PluginMetadata {
    pub id: String,
    pub name: String,
    pub version: String,
    pub description: String,
    pub author: String,
    pub homepage: Option<String>,
    pub license: String,
    pub min_server_version: String,
    pub priority: i32,
    pub capabilities: Vec<String>,
    pub permissions: Vec<String>,
}

// ============================================================================
// 插件配置
// ============================================================================

/// 插件配置
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PluginConfig {
    pub enabled: bool,
    pub priority: Option<i32>,
    pub timeout_ms: Option<u64>,
    pub custom: HashMap<String, serde_json::Value>,
}

impl PluginConfig {
    pub fn get<T: serde::de::DeserializeOwned>(&self, key: &str) -> Option<T> {
        self.custom.get(key).and_then(|v| {
            serde_json::from_value(v.clone()).ok()
        })
    }
}

// ============================================================================
// 插件数据结构
// ============================================================================

/// HTTP 请求
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PluginRequest {
    pub method: String,
    pub path: String,
    pub query: HashMap<String, String>,
    pub headers: HashMap<String, String>,
    pub body: Option<String>,  // Base64 encoded
    pub client_ip: String,
    pub request_id: String,
    pub version: String,
    pub host: String,
}

impl PluginRequest {
    pub fn header(&self, name: &str) -> Option<&String> {
        self.headers.get(&name.to_lowercase())
    }

    pub fn query(&self, name: &str) -> Option<&String> {
        self.query.get(name)
    }
}

/// HTTP 响应
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PluginResponse {
    pub status: u16,
    pub headers: HashMap<String, String>,
    pub body: Option<String>,  // Base64 encoded
}

impl PluginResponse {
    pub fn new(status: u16) -> Self {
        Self {
            status,
            headers: HashMap::new(),
            body: None,
        }
    }

    pub fn ok() -> Self {
        Self::new(200)
    }

    pub fn not_found() -> Self {
        Self::new(404)
    }

    pub fn internal_error() -> Self {
        Self::new(500)
    }

    pub fn with_header(mut self, name: String, value: String) -> Self {
        self.headers.insert(name, value);
        self
    }

    pub fn with_body(mut self, body: String) -> Self {
        self.body = Some(body);
        self
    }

    pub fn json<T: Serialize>(mut self, data: &T) -> Result<Self, PluginError> {
        let json = serde_json::to_string(data)
            .map_err(|e| PluginError::Serialization(e.to_string()))?;
        self.headers.insert("content-type".to_string(), "application/json".to_string());
        self.body = Some(base64_encode(&json));
        Ok(self)
    }
}

// ============================================================================
// 插件动作
// ============================================================================

/// 插件执行结果
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum PluginAction {
    /// 继续执行
    Continue,

    /// 拦截并返回响应
    Intercept(PluginResponse),

    /// 修改请求
    ModifyRequest(PluginRequest),

    /// 修改响应
    ModifyResponse(PluginResponse),

    /// 错误
    Error { message: String },
}

// ============================================================================
// 插件错误
// ============================================================================

/// 插件错误
#[derive(Debug, Error)]
pub enum PluginError {
    #[error("Initialization failed: {0}")]
    InitFailed(String),

    #[error("Invalid configuration: {0}")]
    InvalidConfig(String),

    #[error("Execution error: {0}")]
    ExecutionError(String),

    #[error("Timeout after {0}ms")]
    Timeout(u64),

    #[error("Permission denied: {0}")]
    PermissionDenied(String),

    #[error("Serialization error: {0}")]
    Serialization(String),

    #[error("Invalid input: {0}")]
    InvalidInput(String),

    #[error("{0}")]
    Other(String),
}

// ============================================================================
// 插件 Trait
// ============================================================================

/// 插件主 trait
/// 
/// 所有插件必须实现此 trait
pub trait Plugin: Send + Sync {
    /// 返回插件元数据
    fn metadata(&self) -> &PluginMetadata;

    /// 插件加载时调用
    fn on_load(&mut self, config: &PluginConfig) -> Result<(), PluginError> {
        let _ = config;
        Ok(())
    }

    /// 配置变更时调用
    fn on_config_change(&mut self, _new_config: &PluginConfig) -> Result<(), PluginError> {
        Ok(())
    }

    /// 处理 HTTP 请求
    fn on_request(&mut self, request: &mut PluginRequest) -> Result<PluginAction, PluginError> {
        let _ = request;
        Ok(PluginAction::Continue)
    }

    /// 处理 HTTP 响应
    fn on_response(&mut self, response: &mut PluginResponse) -> Result<PluginAction, PluginError> {
        let _ = response;
        Ok(PluginAction::Continue)
    }

    /// 插件卸载时调用
    fn on_unload(&mut self) -> Result<(), PluginError> {
        Ok(())
    }
}

// ============================================================================
// 辅助函数
// ============================================================================

/// Base64 编码
pub fn base64_encode(data: &str) -> String {
    use base64::Engine;
    base64::engine::general_purpose::STANDARD.encode(data.as_bytes())
}

/// Base64 解码
pub fn base64_decode(data: &str) -> Result<String, PluginError> {
    use base64::Engine;
    base64::engine::general_purpose::STANDARD
        .decode(data)
        .map(|v| String::from_utf8(v).unwrap_or_default())
        .map_err(|e| PluginError::Serialization(e.to_string()))
}

// ============================================================================
// 插件导出宏
// ============================================================================

/// 导出插件
/// 
/// 在插件 crate 的 lib.rs 中使用：
/// 
/// ```ignore
/// rust_serv_plugin::export_plugin!(MyPlugin);
/// ```
#[macro_export]
macro_rules! export_plugin {
    ($plugin_type:ty) => {
        /// 插件实例（全局）
        static mut PLUGIN: Option<$plugin_type> = None;

        /// 初始化插件
        #[no_mangle]
        pub extern "C" fn plugin_init(
            config_ptr: i32,
            config_len: i32,
        ) -> i32 {
            unsafe {
                if PLUGIN.is_some() {
                    return 1000; // Already initialized
                }

                let config = parse_config(config_ptr, config_len);
                let mut plugin = <$plugin_type>::default();

                match plugin.on_load(&config) {
                    Ok(()) => {
                        PLUGIN = Some(plugin);
                        0
                    }
                    Err(e) => {
                        eprintln!("Plugin init failed: {}", e);
                        1001
                    }
                }
            }
        }

        /// 处理请求
        #[no_mangle]
        pub extern "C" fn plugin_on_request(
            req_ptr: i32,
            req_len: i32,
            action_ptr: i32,
            action_len_ptr: i32,
        ) -> i32 {
            unsafe {
                if let Some(ref mut plugin) = PLUGIN {
                    let mut req = parse_request(req_ptr, req_len);
                    match plugin.on_request(&mut req) {
                        Ok(action) => {
                            write_action(action, action_ptr, action_len_ptr);
                            0
                        }
                        Err(e) => {
                            write_action(
                                PluginAction::Error { message: e.to_string() },
                                action_ptr,
                                action_len_ptr,
                            );
                            2000
                        }
                    }
                } else {
                    1002 // Not initialized
                }
            }
        }

        /// 处理响应
        #[no_mangle]
        pub extern "C" fn plugin_on_response(
            res_ptr: i32,
            res_len: i32,
            action_ptr: i32,
            action_len_ptr: i32,
        ) -> i32 {
            unsafe {
                if let Some(ref mut plugin) = PLUGIN {
                    let mut res = parse_response(res_ptr, res_len);
                    match plugin.on_response(&mut res) {
                        Ok(action) => {
                            write_action(action, action_ptr, action_len_ptr);
                            0
                        }
                        Err(e) => {
                            write_action(
                                PluginAction::Error { message: e.to_string() },
                                action_ptr,
                                action_len_ptr,
                            );
                            2000
                        }
                    }
                } else {
                    1002 // Not initialized
                }
            }
        }

        /// 卸载插件
        #[no_mangle]
        pub extern "C" fn plugin_unload() -> i32 {
            unsafe {
                if let Some(mut plugin) = PLUGIN.take() {
                    match plugin.on_unload() {
                        Ok(()) => 0,
                        Err(_) => 1003,
                    }
                } else {
                    0
                }
            }
        }
    };
}

