// Example: Rate Limiter Plugin
//
// A more advanced plugin that implements rate limiting.
// Demonstrates:
// - Plugin state management
// - Request inspection
// - Response modification
// - Using host functions

#![no_std]
#![no_main]

use core::panic::PanicInfo;
use core::sync::atomic::{AtomicU64, Ordering};

#[panic_handler]
fn panic(_info: &PanicInfo) -> ! {
    loop {}
}

// Memory for communication
static mut MEMORY: [u8; 131072] = [0; 131072];

// Rate limit state (simple counter)
static REQUEST_COUNT: AtomicU64 = AtomicU64::new(0);
static mut RATE_LIMIT: u64 = 100; // 100 requests per second

#[no_mangle]
pub extern "C" fn plugin_init(_config_ptr: i32, _config_len: i32) -> i32 {
    // In real implementation, would parse config and set RATE_LIMIT
    REQUEST_COUNT.store(0, Ordering::Relaxed);
    0
}

#[no_mangle]
pub extern "C" fn plugin_on_request(_req_ptr: i32, _req_len: i32, result_ptr: i32) -> i32 {
    // Check rate limit
    let count = REQUEST_COUNT.fetch_add(1, Ordering::Relaxed);

    unsafe {
        if count > RATE_LIMIT {
            // Rate limit exceeded - return 429 error
            let action = br#"{"Intercept":{"status":429,"headers":{"X-RateLimit":"exceeded"},"body":"eyJtZXNzYWdlIjoiUmF0ZSBsaW1pdCBleGNlZWRlZCJ9"}}"#;

            let offset = result_ptr as usize;
            MEMORY[offset..offset+action.len()].copy_from_slice(action);
            MEMORY[offset+action.len()] = 0;

            0
        } else {
            // Continue
            let msg = b"Continue";
            let offset = result_ptr as usize;
            MEMORY[offset..offset+msg.len()].copy_from_slice(msg);
            MEMORY[offset+msg.len()] = 0;

            0
        }
    }
}

#[no_mangle]
pub extern "C" fn plugin_on_response(_res_ptr: i32, _res_len: i32, result_ptr: i32) -> i32 {
    // Add rate limit header to response
    let count = REQUEST_COUNT.load(Ordering::Relaxed);

    unsafe {
        // For simplicity, just continue
        // In real implementation, would modify response headers
        let msg = b"Continue";
        let offset = result_ptr as usize;
        MEMORY[offset..offset+msg.len()].copy_from_slice(msg);
        MEMORY[offset+msg.len()] = 0;
    }

    0
}

#[no_mangle]
pub extern "C" fn plugin_unload() -> i32 {
    0
}

#[no_mangle]
pub extern "C" fn memory() -> *mut u8 {
    unsafe { MEMORY.as_mut_ptr() }
}

//! Access log entry and formatting

use std::time::SystemTime;

/// Access log entry
#[derive(Debug, Clone)]
pub struct AccessLogEntry {
    /// Client IP address
    pub client_ip: String,
    /// Request timestamp
    pub timestamp: SystemTime,
    /// HTTP method
    pub method: String,
    /// Request path
    pub path: String,
    /// HTTP version
    pub version: String,
    /// Response status code
    pub status: u16,
    /// Response size in bytes
    pub size: usize,
    /// Request duration in milliseconds
    pub duration_ms: u64,
    /// User-Agent header
    pub user_agent: Option<String>,
    /// Referer header
    pub referer: Option<String>,
}

impl AccessLogEntry {
    /// Create a new access log entry
    pub fn new(
        client_ip: impl Into<String>,
        method: impl Into<String>,
        path: impl Into<String>,
    ) -> Self {
        Self {
            client_ip: client_ip.into(),
            timestamp: SystemTime::now(),
            method: method.into(),
            path: path.into(),
            version: "HTTP/1.1".to_string(),
            status: 200,
            size: 0,
            duration_ms: 0,
            user_agent: None,
            referer: None,
        }
    }

    /// Set HTTP version
    pub fn with_version(mut self, version: impl Into<String>) -> Self {
        self.version = version.into();
        self
    }

    /// Set response status
    pub fn with_status(mut self, status: u16) -> Self {
        self.status = status;
        self
    }

    /// Set response size
    pub fn with_size(mut self, size: usize) -> Self {
        self.size = size;
        self
    }

    /// Set request duration
    pub fn with_duration_ms(mut self, duration_ms: u64) -> Self {
        self.duration_ms = duration_ms;
        self
    }

    /// Set User-Agent
    pub fn with_user_agent(mut self, user_agent: impl Into<String>) -> Self {
        self.user_agent = Some(user_agent.into());
        self
    }

    /// Set Referer
    pub fn with_referer(mut self, referer: impl Into<String>) -> Self {
        self.referer = Some(referer.into());
        self
    }
}

/// Log format type
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum LogFormat {
    /// Common Log Format (CLF)
    Common,
    /// Combined Log Format
    Combined,
    /// JSON format
    Json,
}

impl Default for LogFormat {
    fn default() -> Self {
        Self::Combined
    }
}

impl LogFormat {
    /// Format a log entry
    pub fn format(&self, entry: &AccessLogEntry) -> String {
        match self {
            LogFormat::Common => self.format_common(entry),
            LogFormat::Combined => self.format_combined(entry),
            LogFormat::Json => self.format_json(entry),
        }
    }

    /// Common Log Format
    fn format_common(&self, entry: &AccessLogEntry) -> String {
        let timestamp = self.format_timestamp(&entry.timestamp);
        format!(
            "{} - - [{}] \"{} {} {}\" {} {}",
            entry.client_ip,
            timestamp,
            entry.method,
            entry.path,
            entry.version,
            entry.status,
            entry.size
        )
    }

    /// Combined Log Format
    fn format_combined(&self, entry: &AccessLogEntry) -> String {
        let timestamp = self.format_timestamp(&entry.timestamp);
        let referer = entry.referer.as_deref().unwrap_or("-");
        let user_agent = entry.user_agent.as_deref().unwrap_or("-");
        format!(
            "{} - - [{}] \"{} {} {}\" {} {} \"{}\" \"{}\"",
            entry.client_ip,
            timestamp,
            entry.method,
            entry.path,
            entry.version,
            entry.status,
            entry.size,
            referer,
            user_agent
        )
    }

    /// JSON format
    fn format_json(&self, entry: &AccessLogEntry) -> String {
        let timestamp = self.format_timestamp_iso(&entry.timestamp);
        let referer = entry.referer.as_deref().unwrap_or("-");
        let user_agent = entry.user_agent.as_deref().unwrap_or("-");

        format!(
            r#"{{"client_ip":"{}","timestamp":"{}","method":"{}","path":"{}","version":"{}","status":{},"size":{},"duration_ms":{},"referer":"{}","user_agent":"{}"}}"#,
            entry.client_ip,
            timestamp,
            entry.method,
            entry.path,
            entry.version,
            entry.status,
            entry.size,
            entry.duration_ms,
            referer,
            user_agent
        )
    }

    /// Format timestamp in CLF format
    fn format_timestamp(&self, time: &SystemTime) -> String {
        use std::time::UNIX_EPOCH;
        let duration = time.duration_since(UNIX_EPOCH).unwrap_or_default();
        let secs = duration.as_secs();

        // Simple date formatting (without chrono dependency)
        let days = secs / 86400;
        let years = 1970 + days / 365;
        let day_of_year = days % 365;
        let months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", 
                      "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

        let hour = (secs % 86400) / 3600;
        let min = (secs % 3600) / 60;
        let sec = secs % 60;

        let month_idx = (day_of_year / 30) as usize;
        let month = months.get(month_idx).unwrap_or(&"Jan");
        let day = (day_of_year % 30) + 1;

        format!("{:02}/{}/{}:{:02}:{:02}:{:02} +0000", day, month, years, hour, min, sec)
    }

    /// Format timestamp in ISO 8601 format
    fn format_timestamp_iso(&self, time: &SystemTime) -> String {
        use std::time::UNIX_EPOCH;
        let duration = time.duration_since(UNIX_EPOCH).unwrap_or_default();
        let secs = duration.as_secs();

        let days = secs / 86400;
        let years = 1970 + days / 365;
        let day_of_year = days % 365;
        let month = (day_of_year / 30) + 1;
        let day = (day_of_year % 30) + 1;
        let hour = (secs % 86400) / 3600;
        let min = (secs % 3600) / 60;
        let sec = secs % 60;

        format!("{}-{:02}-{:02}T{:02}:{:02}:{:02}Z", years, month, day, hour, min, sec)
    }
}

