//! Access log persistence module
//!
//! This module provides access logging and file persistence capabilities.

mod formatter;
mod writer;

pub use formatter::{AccessLogEntry, LogFormat};
pub use writer::AccessLogWriter;

//! Access log writer with file persistence

use std::fs::{File, OpenOptions};
use std::io::Write as IoWrite;
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};

use super::formatter::{AccessLogEntry, LogFormat};

/// Access log writer
pub struct AccessLogWriter {
    /// Log file path
    path: PathBuf,
    /// Log format
    format: LogFormat,
    /// Output file
    file: Arc<Mutex<File>>,
}

impl AccessLogWriter {
    /// Create a new access log writer
    pub fn new<P: AsRef<Path>>(path: P) -> std::io::Result<Self> {
        Self::with_format(path, LogFormat::default())
    }

    /// Create a new access log writer with custom format
    pub fn with_format<P: AsRef<Path>>(path: P, format: LogFormat) -> std::io::Result<Self> {
        let path = path.as_ref().to_path_buf();

        // Create parent directories if needed
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }

        let file = OpenOptions::new()
            .create(true)
            .append(true)
            .open(&path)?;

        Ok(Self {
            path,
            format,
            file: Arc::new(Mutex::new(file)),
        })
    }

    /// Write a log entry
    pub fn write(&self, entry: &AccessLogEntry) -> std::io::Result<()> {
        let line = self.format.format(entry);
        let mut file = self.file.lock().unwrap();
        writeln!(file, "{}", line)?;
        file.flush()?;
        Ok(())
    }

    /// Write multiple log entries
    pub fn write_batch(&self, entries: &[AccessLogEntry]) -> std::io::Result<()> {
        let mut file = self.file.lock().unwrap();
        for entry in entries {
            let line = self.format.format(entry);
            writeln!(file, "{}", line)?;
        }
        file.flush()?;
        Ok(())
    }

    /// Get the log file path
    pub fn path(&self) -> &Path {
        &self.path
    }

    /// Get the log format
    pub fn format(&self) -> LogFormat {
        self.format
    }

    /// Flush the file buffer
    pub fn flush(&self) -> std::io::Result<()> {
        let mut file = self.file.lock().unwrap();
        file.flush()
    }
}

impl Clone for AccessLogWriter {
    fn clone(&self) -> Self {
        Self {
            path: self.path.clone(),
            format: self.format,
            file: Arc::clone(&self.file),
        }
    }
}

