    /// ACME protocol error
    #[error("ACME error: {0}")]
    AcmeError(String),

    /// Challenge error
    #[error("Challenge error: {0}")]
    ChallengeError(String),

    /// Certificate error
    #[error("Certificate error: {0}")]
    CertificateError(String),

    /// IO error
    #[error("IO error: {0}")]
    IoError(#[from] std::io::Error),

    /// Configuration error
    #[error("Configuration error: {0}")]
