        assert!(cert.is_expired());
        assert!(cert.days_until_expiry() <= 0);
    }

    #[test]
    fn test_stored_certificate_serialization() {
        let cert = StoredCertificate::new(
            "example.com".to_string(),
            "cert_pem".to_string(),
            "key_pem".to_string(),
            1234567890,
        );

        let json = serde_json::to_string(&cert).unwrap();
        let parsed: StoredCertificate = serde_json::from_str(&json).unwrap();

        assert_eq!(parsed.domain, cert.domain);
        assert_eq!(parsed.certificate, cert.certificate);
        assert_eq!(parsed.expires_at, cert.expires_at);
    }

    #[tokio::test]
    async fn test_certificate_store_paths() {
        let dir = tempdir().unwrap();
        let store = CertificateStore::new(dir.path());

        assert_eq!(store.account_path(), dir.path().join("account.json"));
        assert_eq!(
            store.certificate_path("example.com"),
            dir.path().join("example.com.json")
        );
        assert_eq!(
            store.cert_pem_path("example.com"),
            dir.path().join("example.com.crt")
        );
        assert_eq!(
            store.key_pem_path("example.com"),
            dir.path().join("example.com.key")
        );
    }

    #[tokio::test]
    async fn test_certificate_store_save_load() {
        let dir = tempdir().unwrap();
        let store = CertificateStore::new(dir.path());

        store.save_certificate("example.com", "cert", "key").await.unwrap();

        let loaded = store.load_certificate("example.com").await.unwrap();
        assert!(loaded.is_some());

        let cert = loaded.unwrap();
        assert_eq!(cert.domain, "example.com");
        assert_eq!(cert.certificate, "cert");
        assert_eq!(cert.private_key, "key");
    }

    #[tokio::test]
    async fn test_certificate_store_delete() {
        let dir = tempdir().unwrap();
        let store = CertificateStore::new(dir.path());

        store.save_certificate("example.com", "cert", "key").await.unwrap();
        store.delete_certificate("example.com").await.unwrap();

        let loaded = store.load_certificate("example.com").await.unwrap();
        assert!(loaded.is_none());
    }

    #[tokio::test]
    async fn test_certificate_store_list() {
        let dir = tempdir().unwrap();
        let store = CertificateStore::new(dir.path());

        store.save_certificate("example.com", "cert1", "key1").await.unwrap();
        store.save_certificate("test.com", "cert2", "key2").await.unwrap();

        let domains = store.list_certificates().await.unwrap();
        assert_eq!(domains.len(), 2);
        assert!(domains.contains(&"example.com".to_string()));
        assert!(domains.contains(&"test.com".to_string()));
    }

    #[tokio::test]
    async fn test_certificate_store_init() {
        let dir = tempdir().unwrap();
        let new_dir = dir.path().join("new_cache");
        let store = CertificateStore::new(&new_dir);

        assert!(!new_dir.exists());
        store.init().await.unwrap();
        assert!(new_dir.exists());
    }
}

//! Basic Authenticator

use super::credentials::Credentials;
use super::validator::AuthValidator;

/// Basic authenticator
pub struct BasicAuthenticator {
    validator: AuthValidator,
    realm: String,
}

impl BasicAuthenticator {
    /// Create a new basic authenticator
    pub fn new(validator: AuthValidator) -> Self {
        Self {
            validator,
            realm: "Protected Area".to_string(),
        }
    }

    /// Create a new basic authenticator with custom realm
    pub fn with_realm(validator: AuthValidator, realm: impl Into<String>) -> Self {
        Self {
            validator,
            realm: realm.into(),
        }
    }

    /// Get the realm
    pub fn realm(&self) -> &str {
        &self.realm
    }

    /// Check if path requires authentication
    pub fn requires_auth(&self, path: &str) -> bool {
        self.validator.requires_auth(path)
    }

    /// Authenticate a request using Basic Auth header
    pub fn authenticate(&self, auth_header: Option<&str>) -> AuthResult {
        match auth_header {
            Some(header) => {
                match Credentials::from_header(header) {
                    Some(creds) => {
                        if self.validator.validate(&creds) {
                            AuthResult::Success(creds.username)
                        } else {
                            AuthResult::InvalidCredentials
                        }
                    }
                    None => AuthResult::InvalidHeader,
                }
            }
            None => AuthResult::MissingHeader,
        }
    }

    /// Get the WWW-Authenticate header value for 401 responses
    pub fn www_authenticate_header(&self) -> String {
        format!("Basic realm=\"{}\"", self.realm)
    }

    /// Get the validator
    pub fn validator(&self) -> &AuthValidator {
        &self.validator
    }

    /// Get mutable validator
    pub fn validator_mut(&mut self) -> &mut AuthValidator {
        &mut self.validator
    }
}

/// Authentication result
#[derive(Debug, Clone, PartialEq)]
pub enum AuthResult {
    /// Authentication successful, contains username
    Success(String),
    /// Missing Authorization header
    MissingHeader,
    /// Invalid Authorization header format
    InvalidHeader,
    /// Invalid credentials
    InvalidCredentials,
}

impl AuthResult {
    /// Check if authentication was successful
    pub fn is_success(&self) -> bool {
        matches!(self, AuthResult::Success(_))
    }

    /// Get username if successful
    pub fn username(&self) -> Option<&str> {
        match self {
            AuthResult::Success(username) => Some(username),
            _ => None,
        }
    }

    /// Get the HTTP status code for this result
    pub fn status_code(&self) -> u16 {
        match self {
            AuthResult::Success(_) => 200,
            _ => 401,
        }
    }
}

