    #[test]
    fn test_stats_evictions() {
        let cache = create_test_cache();

        // Fill cache
        for i in 0..10 {
            let path = make_path(&format!("/file{}.txt", i));
            cache.insert(
                path,
                Bytes::from("x"),
                "text/plain".to_string(),
                format!("\"etag{}\"", i),
                0,
            );
        }

        // Insert one more to trigger eviction
        let path = make_path("/overflow.txt");
        cache.insert(path, Bytes::from("y"), "text/plain".to_string(), "\"overflow\"".to_string(), 0);

        assert!(cache.stats().evictions() > 0);
    }

    #[test]
    fn test_concurrent_access() {
        use std::thread;

        let cache = Arc::new(create_test_cache());
        let mut handles = vec![];

        // Spawn multiple threads for concurrent writes
        for i in 0..5 {
            let cache_clone = Arc::clone(&cache);
            handles.push(thread::spawn(move || {
                let path = make_path(&format!("/file{}.txt", i));
                cache_clone.insert(
                    path,
                    Bytes::from(format!("content{}", i)),
                    "text/plain".to_string(),
                    format!("\"etag{}\"", i),
                    0,
                );
            }));
        }

        for handle in handles {
            handle.join().unwrap();
        }

        assert_eq!(cache.len(), 5);
    }

    #[test]
    fn test_concurrent_reads() {
        use std::thread;

        let cache = Arc::new(create_test_cache());

        // Insert a file
        let path = make_path("/test.txt");
        cache.insert(
            path.clone(),
            Bytes::from("test content"),
            "text/plain".to_string(),
            "\"etag\"".to_string(),
            0,
        );

        let mut handles = vec![];

        // Spawn multiple threads for concurrent reads
        for _ in 0..10 {
            let cache_clone = Arc::clone(&cache);
            let path_clone = path.clone();
            handles.push(thread::spawn(move || {
                cache_clone.get(&path_clone)
            }));
        }

        let results: Vec<_> = handles.into_iter().map(|h| h.join().unwrap()).collect();

        // All reads should succeed
        assert!(results.iter().all(|r| r.is_some()));
        assert_eq!(cache.stats().hits(), 10);
    }

    #[test]
    fn test_stats_total_size() {
        let cache = create_test_cache();

        cache.insert(
            make_path("/file1.txt"),
            Bytes::from("12345"), // 5 bytes
            "text/plain".to_string(),
            "\"e1\"".to_string(),
            0,
        );

        assert_eq!(cache.stats().total_size(), 5);

        cache.insert(
            make_path("/file2.txt"),
            Bytes::from("67890"), // 5 bytes
            "text/plain".to_string(),
            "\"e2\"".to_string(),
            0,
        );

        assert_eq!(cache.stats().total_size(), 10);
    }

    #[test]
    fn test_hit_rate_calculation() {
        let cache = create_test_cache();
        let path = make_path("/test.txt");

        // 2 misses
        cache.get(&path);
        cache.get(&path);

        // Insert
        cache.insert(
            path.clone(),
            Bytes::from("test"),
            "text/plain".to_string(),
            "\"etag\"".to_string(),
            0,
        );

        // 3 hits
        cache.get(&path);
        cache.get(&path);
        cache.get(&path);

        // Hit rate should be 60% (3 hits / 5 total requests)
        let expected = 3.0 / 5.0;
        assert!((cache.stats().hit_rate() - expected).abs() < 0.001);
    }
}

//! Cached file representation

use std::time::{Duration, Instant};
use bytes::Bytes;

/// A cached file with metadata
#[derive(Clone, Debug)]
pub struct CachedFile {
    /// File content
    pub content: Bytes,
    /// MIME type
    pub mime_type: String,
    /// ETag for cache validation
    pub etag: String,
    /// Last modified timestamp (Unix timestamp)
    pub last_modified: u64,
    /// When this cache entry was created
    pub created_at: Instant,
    /// Time-to-live duration
    pub ttl: Duration,
    /// File size in bytes
    pub size: usize,
}

impl CachedFile {
    /// Create a new cached file
    pub fn new(
        content: Bytes,
        mime_type: String,
        etag: String,
        last_modified: u64,
        ttl: Duration,
    ) -> Self {
        let size = content.len();
        Self {
            content,
            mime_type,
            etag,
            last_modified,
            created_at: Instant::now(),
            ttl,
            size,
        }
    }

    /// Check if the cache entry has expired
    pub fn is_expired(&self) -> bool {
        self.created_at.elapsed() > self.ttl
    }

    /// Get the age of the cache entry
    pub fn age(&self) -> Duration {
        self.created_at.elapsed()
    }

    /// Check if the ETag matches
    pub fn etag_matches(&self, etag: &str) -> bool {
        self.etag == etag
    }
}

