//! Memory cache module for high-performance file caching
//! 
//! This module provides an in-memory LRU cache for frequently accessed files,
//! reducing disk I/O and improving response times.

mod cache;
mod cached_file;
mod stats;

pub use cache::{CacheConfig, MemoryCache};
pub use cached_file::CachedFile;
pub use stats::CacheStats;

//! Cache statistics for monitoring

use std::sync::atomic::{AtomicU64, Ordering};

/// Cache statistics
#[derive(Debug, Default)]
pub struct CacheStats {
    /// Number of cache hits
    hits: AtomicU64,
    /// Number of cache misses
    misses: AtomicU64,
    /// Number of cache evictions
    evictions: AtomicU64,
    /// Number of cache entries
    entries: AtomicU64,
    /// Total size of cached data in bytes
    total_size: AtomicU64,
    /// Number of expired entries removed
    expired: AtomicU64,
}

impl CacheStats {
    /// Create new cache statistics
    pub fn new() -> Self {
        Self::default()
    }

    /// Record a cache hit
    pub fn record_hit(&self) {
        self.hits.fetch_add(1, Ordering::Relaxed);
    }

    /// Record a cache miss
    pub fn record_miss(&self) {
        self.misses.fetch_add(1, Ordering::Relaxed);
    }

    /// Record a cache eviction
    pub fn record_eviction(&self) {
        self.evictions.fetch_add(1, Ordering::Relaxed);
    }

    /// Record an expired entry removal
    pub fn record_expired(&self) {
        self.expired.fetch_add(1, Ordering::Relaxed);
    }

    /// Add to entry count
    pub fn add_entry(&self, size: usize) {
        self.entries.fetch_add(1, Ordering::Relaxed);
        self.total_size.fetch_add(size as u64, Ordering::Relaxed);
    }

    /// Remove from entry count
    pub fn remove_entry(&self, size: usize) {
        self.entries.fetch_sub(1, Ordering::Relaxed);
        self.total_size.fetch_sub(size as u64, Ordering::Relaxed);
    }

    /// Update size (delta can be positive or negative)
    pub fn update_size(&self, delta: i64) {
        if delta >= 0 {
            self.total_size.fetch_add(delta as u64, Ordering::Relaxed);
        } else {
            self.total_size.fetch_sub((-delta) as u64, Ordering::Relaxed);
        }
    }

    /// Get cache hits
    pub fn hits(&self) -> u64 {
        self.hits.load(Ordering::Relaxed)
    }

    /// Get cache misses
    pub fn misses(&self) -> u64 {
        self.misses.load(Ordering::Relaxed)
    }

    /// Get cache evictions
    pub fn evictions(&self) -> u64 {
        self.evictions.load(Ordering::Relaxed)
    }

    /// Get number of entries
    pub fn entries(&self) -> u64 {
        self.entries.load(Ordering::Relaxed)
    }

    /// Get total size in bytes
    pub fn total_size(&self) -> u64 {
        self.total_size.load(Ordering::Relaxed)
    }

    /// Get expired count
    pub fn expired(&self) -> u64 {
        self.expired.load(Ordering::Relaxed)
    }

    /// Calculate hit rate (0.0 to 1.0)
    pub fn hit_rate(&self) -> f64 {
        let hits = self.hits();
        let misses = self.misses();
        let total = hits + misses;
        if total == 0 {
            0.0
        } else {
            hits as f64 / total as f64
        }
    }

    /// Get total requests
    pub fn total_requests(&self) -> u64 {
        self.hits() + self.misses()
    }

    /// Reset statistics
    pub fn reset(&self) {
        self.hits.store(0, Ordering::Relaxed);
        self.misses.store(0, Ordering::Relaxed);
        self.evictions.store(0, Ordering::Relaxed);
        self.entries.store(0, Ordering::Relaxed);
        self.total_size.store(0, Ordering::Relaxed);
        self.expired.store(0, Ordering::Relaxed);
    }
}

