//! Security Middleware
//!
//! This module implements comprehensive security features:
//! - Rate limiting for request throttling
//! - IP access control (allowlist/blocklist)
//! - Security headers (CSP, HSTS, X-Frame-Options, etc.)
//! - Request size limits
//! - Input validation
//!
//! ## Security Features
//!
//! ### Rate Limiting
//! - Request rate limiting per IP address
//! - Token bucket algorithm
//! - Configurable limits and windows
//!
//! ### IP Access Control
//! - IP allowlist (whitelist)
//! - IP blocklist (blacklist)
//! - CIDR notation support
//!
//! ### Security Headers
//! - Content-Security-Policy (CSP)
//! - HTTP Strict Transport Security (HSTS)
//! - X-Frame-Options
//! - X-Content-Type-Options
//! - X-XSS-Protection
//! - Referrer-Policy
//!
//! ### Request Size Limits
//! - Maximum request body size
//! - Maximum header size
//! - Prevent DoS attacks

use hyper::HeaderMap;
use hyper::header::{
    CONTENT_SECURITY_POLICY, STRICT_TRANSPORT_SECURITY, X_FRAME_OPTIONS,
    X_CONTENT_TYPE_OPTIONS, X_XSS_PROTECTION, REFERRER_POLICY,
    CONTENT_LENGTH, HeaderValue
};
use std::collections::HashMap;
use std::net::{Ipv4Addr, Ipv6Addr};
use std::sync::Arc;
use std::time::{Duration, Instant};
use tokio::sync::RwLock;

/// Rate limiting configuration
#[derive(Debug, Clone)]
pub struct RateLimitConfig {
    /// Maximum number of requests per time window
    pub max_requests: usize,

    /// Time window in seconds
    pub window_secs: u64,

    /// Whether rate limiting is enabled
    pub enabled: bool,
}

impl Default for RateLimitConfig {
    fn default() -> Self {
        Self {
            max_requests: 100,  // 100 requests
            window_secs: 60,    // per minute
            enabled: true,
        }
    }
}

/// IP access control configuration
#[derive(Debug, Clone)]
pub struct IpAccessConfig {
    /// List of allowed IP addresses (empty = all allowed)
    pub allowlist: Vec<String>,

    /// List of blocked IP addresses
    pub blocklist: Vec<String>,

    /// Whether IP access control is enabled
    pub enabled: bool,
}

impl Default for IpAccessConfig {
    fn default() -> Self {
        Self {
            allowlist: vec![],
            blocklist: vec![],
            enabled: false,
        }
    }
}

/// Security headers configuration
#[derive(Debug, Clone)]
pub struct SecurityHeadersConfig {
