//! Plugin file watcher for hot-reload

use crate::plugin::{
    error::{PluginError, PluginResult},
    manager::PluginManager,
};
use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::Duration;
use tokio::sync::mpsc;
use notify::{Watcher, RecommendedWatcher, RecursiveMode, Event, EventKind};

/// Plugin watcher for hot-reload
pub struct PluginWatcher {
    watcher: RecommendedWatcher,
    watched_paths: Vec<PathBuf>,
}

impl PluginWatcher {
    /// Create a new plugin watcher
    pub fn new(manager: Arc<tokio::sync::RwLock<PluginManager>>) -> PluginResult<Self> {
        let (tx, mut rx) = mpsc::unbounded_channel();

        // Create file watcher
        let mut watcher = notify::recommended_watcher(move |res: Result<Event, notify::Error>| {
            if let Ok(event) = res {
                let _ = tx.send(event);
            }
        }).map_err(|e| PluginError::WatcherError(e.to_string()))?;

        // Spawn task to handle file changes
        tokio::spawn(async move {
            while let Some(event) = rx.recv().await {
                if let Err(e) = handle_file_event(&manager, &event).await {
                    eprintln!("Plugin watcher error: {}", e);
                }
            }
        });

        Ok(Self {
            watcher,
            watched_paths: vec![],
        })
    }

    /// Watch a directory for plugin changes
    pub fn watch(&mut self, path: &Path) -> PluginResult<()> {
        self.watcher.watch(path, RecursiveMode::Recursive)
            .map_err(|e| PluginError::WatcherError(e.to_string()))?;

        self.watched_paths.push(path.to_path_buf());

        Ok(())
    }

    /// Stop watching a path
    pub fn unwatch(&mut self, path: &Path) -> PluginResult<()> {
        self.watcher.unwatch(path)
            .map_err(|e| PluginError::WatcherError(e.to_string()))?;

        self.watched_paths.retain(|p| p != path);

        Ok(())
    }

    /// Get watched paths
    pub fn watched_paths(&self) -> &[PathBuf] {
        &self.watched_paths
    }

    /// Stop all watching
    pub fn stop(&mut self) {
        for path in self.watched_paths.clone() {
            let _ = self.watcher.unwatch(&path);
        }
        self.watched_paths.clear();
    }
}

async fn handle_file_event(
    manager: &Arc<tokio::sync::RwLock<PluginManager>>,
    event: &Event,
) -> PluginResult<()> {
    // Only handle create/modify/remove events
    match event.kind {
        EventKind::Create(_) |
        EventKind::Modify(_) |
        EventKind::Remove(_) => {
            // Check if it's a .wasm file
            for path in &event.paths {
                if path.extension().map(|e| e == "wasm").unwrap_or(false) {
                    println!("Plugin file changed: {:?}", path);

                    // Find plugin ID to reload
                    let plugin_id = {
                        let manager = manager.read().await;
                        manager.list()
                            .iter()
                            .find(|p| p.path == *path)
                            .map(|p| p.id.clone())
                    };

                    // Reload if found
                    if let Some(id) = plugin_id {
                        let mut manager = manager.write().await;
                        println!("Reloading plugin: {}", id);
                        manager.reload(&id)?;
                    }
                }
            }
        }
        _ => {}
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use tokio::runtime::Runtime;

    #[test]
    fn test_watcher_creation() {
        let rt = Runtime::new().unwrap();
        rt.block_on(async {
            let manager = Arc::new(tokio::sync::RwLock::new(PluginManager::new().unwrap()));
            let watcher = PluginWatcher::new(manager);
            assert!(watcher.is_ok());
        });
    }
}

//! Proxy configuration

use std::time::Duration;

/// Proxy configuration
#[derive(Debug, Clone)]
pub struct ProxyConfig {
    /// Path pattern to match (e.g., "/api")
    pub path: String,
    /// Target URL (e.g., "http://localhost:3000")
    pub target: String,
    /// Strip the matched path prefix before forwarding
    pub strip_prefix: bool,
    /// Connection timeout
    pub timeout: Duration,
    /// Preserve Host header
    pub preserve_host: bool,
    /// Follow redirects
    pub follow_redirects: bool,
}

impl ProxyConfig {
    /// Create a new proxy config
    pub fn new(path: impl Into<String>, target: impl Into<String>) -> Self {
        Self {
            path: path.into(),
            target: target.into(),
            strip_prefix: true,
            timeout: Duration::from_secs(30),
            preserve_host: false,
            follow_redirects: false,
        }
    }

    /// Set strip prefix
    pub fn with_strip_prefix(mut self, strip: bool) -> Self {
        self.strip_prefix = strip;
        self
    }

    /// Set timeout
    pub fn with_timeout(mut self, timeout: Duration) -> Self {
        self.timeout = timeout;
        self
    }

    /// Set preserve host
    pub fn with_preserve_host(mut self, preserve: bool) -> Self {
        self.preserve_host = preserve;
        self
    }

    /// Set follow redirects
    pub fn with_follow_redirects(mut self, follow: bool) -> Self {
        self.follow_redirects = follow;
        self
    }

    /// Check if a path matches this proxy rule
    pub fn matches(&self, path: &str) -> bool {
        path.starts_with(&self.path)
    }

    /// Build target URL for a request path
    pub fn build_target_url(&self, request_path: &str) -> String {
        let target_path = if self.strip_prefix && request_path.starts_with(&self.path) {
            &request_path[self.path.len()..]
        } else {
            request_path
        };

        // Ensure target_path starts with /
        let target_path = if target_path.starts_with('/') {
            target_path.to_string()
        } else if target_path.is_empty() {
            "/".to_string()
        } else {
            format!("/{}", target_path)
        };

        // Combine target and path
        let target = self.target.trim_end_matches('/');
        format!("{}{}", target, target_path)
    }

    /// Parse target into scheme, host, port
    pub fn parse_target(&self) -> Result<(String, String, Option<u16>), String> {
        let target = &self.target;

        // Extract scheme
        let scheme_end = target.find("://").ok_or("Invalid target URL: missing scheme")?;
        let scheme = target[..scheme_end].to_lowercase();

        let rest = &target[scheme_end + 3..];

        // Extract host and port
        let (host, port) = if let Some(port_start) = rest.find(':') {
            let host = rest[..port_start].to_string();
            let port_str = &rest[port_start + 1..];
            let port = port_str.parse::<u16>().map_err(|_| "Invalid port")?;
            (host, Some(port))
        } else {
            (rest.to_string(), None)
        };

        Ok((scheme, host, port))
    }
}

impl Default for ProxyConfig {
    fn default() -> Self {
        Self::new("/api", "http://localhost:3000")
    }
}

