        // Verify Sec-WebSocket-Accept header
        assert_eq!(
            response.headers().get(SEC_WEBSOCKET_ACCEPT).unwrap().to_str().unwrap(),
            "s3pPLMBiTxaQ9kYGzzhZRbK+xOo="
        );
    }

