        let converted = server.to_tungstenite_message(&binary_msg);
        if let Message::Binary(data) = converted {
            assert_eq!(data.to_vec(), binary_data);
        } else {
            panic!("Expected Binary message");
        }
    }

    #[test]
    fn test_websocket_message_close_edge_codes() {
        let config = Config::default();
        let server = WebSocketServer::new(config);

        // Test edge close codes
        let edge_codes = vec![
            0u16,     // Minimum
            999,      // Just below normal
            1000,     // Normal closure
            1001,     // Going away
            2999,     // Application specific range
            3000,     // Application specific
            3999,     // Max application specific
            4000,     // Private use
            4999,     // Max valid code
        ];

        for code in edge_codes {
            let close_frame = tungstenite::protocol::frame::CloseFrame {
                code: tungstenite::protocol::frame::coding::CloseCode::from(code),
                reason: "Test".into(),
            };
            let message = Message::Close(Some(close_frame));
            let result = server.handle_message(message).unwrap();

            match result {
                Some(WebSocketMessage::Close { code: c, .. }) => {
                    assert_eq!(c, code);
                }
                _ => panic!("Expected Close message with code {}", code),
            }
        }
    }

    #[tokio::test]
    async fn test_send_to_all_message_types() {
        let config = Config::default();
        let server = WebSocketServer::new(config);

        let (sender, mut receiver) = mpsc::unbounded_channel();
        server.add_connection("test_conn".to_string(), sender).await;

        // Test all message types via send_to
        let test_cases = vec![
            WebSocketMessage::Text("Hello".to_string()),
            WebSocketMessage::Binary(tungstenite::Bytes::from(vec![1, 2, 3])),
            WebSocketMessage::Ping(tungstenite::Bytes::from(vec![4, 5, 6])),
            WebSocketMessage::Pong(tungstenite::Bytes::from(vec![7, 8, 9])),
            WebSocketMessage::Close {
                code: 1000,
                reason: "Normal".to_string(),
            },
        ];

        for msg in test_cases {
            let msg_clone = msg.clone();
            server.send_to("test_conn", msg).await.unwrap();
            let received = receiver.recv().await.unwrap();
            assert_eq!(received, msg_clone);
        }
    }
}

//! Throttle configuration

use std::time::Duration;

/// Bandwidth throttle configuration
#[derive(Debug, Clone)]
pub struct ThrottleConfig {
    /// Global bandwidth limit in bytes per second (0 = unlimited)
    pub global_limit: u64,
    /// Per-IP bandwidth limit in bytes per second (0 = unlimited)
    pub per_ip_limit: u64,
    /// Bucket capacity (burst size) in bytes
    pub bucket_capacity: u64,
    /// Refill interval
    pub refill_interval: Duration,
    /// Enabled flag
    pub enabled: bool,
}

impl ThrottleConfig {
    /// Create a new throttle config
    pub fn new() -> Self {
        Self {
            global_limit: 0,
            per_ip_limit: 0,
            bucket_capacity: 64 * 1024, // 64KB burst
            refill_interval: Duration::from_millis(100),
            enabled: false,
        }
    }

    /// Set global bandwidth limit (bytes/sec)
    pub fn with_global_limit(mut self, limit: u64) -> Self {
        self.global_limit = limit;
        self
    }

    /// Set per-IP bandwidth limit (bytes/sec)
    pub fn with_per_ip_limit(mut self, limit: u64) -> Self {
        self.per_ip_limit = limit;
        self
    }

    /// Set bucket capacity
    pub fn with_bucket_capacity(mut self, capacity: u64) -> Self {
        self.bucket_capacity = capacity;
        self
    }

    /// Set refill interval
    pub fn with_refill_interval(mut self, interval: Duration) -> Self {
        self.refill_interval = interval;
        self
    }

    /// Enable throttling
    pub fn enable(mut self) -> Self {
        self.enabled = true;
        self
    }

    /// Disable throttling
    pub fn disable(mut self) -> Self {
        self.enabled = false;
        self
    }

    /// Check if global limit is set
    pub fn has_global_limit(&self) -> bool {
        self.enabled && self.global_limit > 0
    }

    /// Check if per-IP limit is set
    pub fn has_per_ip_limit(&self) -> bool {
        self.enabled && self.per_ip_limit > 0
    }

    /// Check if any limit is set
    pub fn is_active(&self) -> bool {
        self.enabled && (self.global_limit > 0 || self.per_ip_limit > 0)
    }

    /// Calculate tokens to add per interval
    pub fn tokens_per_interval(&self, limit: u64) -> u64 {
        let intervals_per_sec = 1000 / self.refill_interval.as_millis() as u64;
        limit / intervals_per_sec
    }

    /// Create a human-readable limit string
    pub fn format_limit(bytes_per_sec: u64) -> String {
        if bytes_per_sec == 0 {
            return "unlimited".to_string();
        }

        const KB: u64 = 1024;
        const MB: u64 = 1024 * KB;
        const GB: u64 = 1024 * MB;

        if bytes_per_sec >= GB {
            format!("{:.1} GB/s", bytes_per_sec as f64 / GB as f64)
        } else if bytes_per_sec >= MB {
            format!("{:.1} MB/s", bytes_per_sec as f64 / MB as f64)
        } else if bytes_per_sec >= KB {
            format!("{:.1} KB/s", bytes_per_sec as f64 / KB as f64)
        } else {
            format!("{} B/s", bytes_per_sec)
        }
    }
}

impl Default for ThrottleConfig {
    fn default() -> Self {
        Self::new()
    }
}

