        limiter.consume("127.0.0.1", 300).await;

        assert_eq!(limiter.global_tokens().await, 700);
    }

    #[tokio::test]
    async fn test_ip_tokens() {
        let config = ThrottleConfig::new()
            .enable()
            .with_per_ip_limit(1000)
            .with_bucket_capacity(1000);

        let limiter = ThrottleLimiter::new(config);

        // New IP should have full bucket
        assert_eq!(limiter.ip_tokens("127.0.0.1").await, 1000);

        limiter.consume("127.0.0.1", 300).await;

        assert_eq!(limiter.ip_tokens("127.0.0.1").await, 700);
    }

    #[tokio::test]
    async fn test_clone() {
        let config = ThrottleConfig::new()
            .enable()
            .with_global_limit(1000)
            .with_bucket_capacity(1000);

        let limiter = ThrottleLimiter::new(config);
        let cloned = limiter.clone();

        // Both should share the same buckets
        limiter.consume("127.0.0.1", 500).await;
        assert_eq!(cloned.global_tokens().await, 500);
    }

    #[test]
    fn test_throttle_result_is_allowed() {
        assert!(ThrottleResult::Allowed { remaining: 100 }.is_allowed());
        assert!(ThrottleResult::Unlimited.is_allowed());
        assert!(!ThrottleResult::Throttled { wait_ms: 100 }.is_allowed());
    }
}

//! Bandwidth throttling module
//!
//! This module provides bandwidth rate limiting using a token bucket algorithm.

mod config;
mod limiter;
mod token_bucket;

pub use config::ThrottleConfig;
pub use limiter::ThrottleLimiter;
pub use token_bucket::TokenBucket;

//! Token bucket implementation for rate limiting

use std::time::{Duration, Instant};

/// Token bucket for rate limiting
#[derive(Debug)]
pub struct TokenBucket {
    /// Maximum tokens in bucket
    capacity: u64,
    /// Current tokens
    tokens: f64,
    /// Tokens added per second
    refill_rate: f64,
    /// Last refill time
    last_refill: Instant,
}

impl TokenBucket {
    /// Create a new token bucket
    pub fn new(capacity: u64, refill_rate: u64) -> Self {
        Self {
            capacity,
            tokens: capacity as f64,
            refill_rate: refill_rate as f64,
            last_refill: Instant::now(),
        }
    }

    /// Get bucket capacity
    pub fn capacity(&self) -> u64 {
        self.capacity
    }

    /// Get refill rate (tokens per second)
    pub fn refill_rate(&self) -> u64 {
        self.refill_rate as u64
    }

    /// Get current token count
    pub fn tokens(&mut self) -> u64 {
        self.refill();
        self.tokens as u64
    }

    /// Refill tokens based on elapsed time
    fn refill(&mut self) {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill);
        let tokens_to_add = elapsed.as_secs_f64() * self.refill_rate;

        self.tokens = (self.tokens + tokens_to_add).min(self.capacity as f64);
        self.last_refill = now;
    }

    /// Try to consume tokens
    /// Returns the number of tokens actually consumed
    pub fn consume(&mut self, requested: u64) -> u64 {
        self.refill();

        if self.tokens >= requested as f64 {
            self.tokens -= requested as f64;
            requested
        } else {
            let consumed = self.tokens as u64;
            self.tokens = 0.0;
            consumed
        }
    }

    /// Try to consume exactly the requested amount
    /// Returns true if successful, false if not enough tokens
    pub fn try_consume(&mut self, amount: u64) -> bool {
        self.refill();

        if self.tokens >= amount as f64 {
            self.tokens -= amount as f64;
            true
        } else {
            false
        }
    }

    /// Wait until enough tokens are available (simulated)
    /// Returns the duration to wait
    pub fn wait_time(&mut self, amount: u64) -> Duration {
        self.refill();

        if self.tokens >= amount as f64 {
            return Duration::ZERO;
        }

        let tokens_needed = amount as f64 - self.tokens;
        let wait_secs = tokens_needed / self.refill_rate;

        Duration::from_secs_f64(wait_secs)
    }

    /// Reset bucket to full capacity
    pub fn reset(&mut self) {
        self.tokens = self.capacity as f64;
        self.last_refill = Instant::now();
    }

    /// Update refill rate
    pub fn set_refill_rate(&mut self, rate: u64) {
        self.refill_rate = rate as f64;
    }

    /// Update capacity
    pub fn set_capacity(&mut self, capacity: u64) {
        self.capacity = capacity;
        self.tokens = self.tokens.min(capacity as f64);
    }

    /// Check if bucket has enough tokens
    pub fn has_tokens(&mut self, amount: u64) -> bool {
        self.refill();
        self.tokens >= amount as f64
    }

    /// Get fill percentage (0.0 to 1.0)
    pub fn fill_level(&mut self) -> f64 {
        self.refill();
        self.tokens / self.capacity as f64
    }
}

impl Clone for TokenBucket {
    fn clone(&self) -> Self {
        Self {
            capacity: self.capacity,
            tokens: self.tokens,
            refill_rate: self.refill_rate,
            last_refill: Instant::now(),
        }
    }
}

